          <ArrowLeft className="mr-2 h-4 w-4" />
          Retour
        </Button>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Product Image */}
          <div className="relative aspect-square rounded-lg overflow-hidden bg-white">
            <img
              src={product.image}
              alt={product.name}
              className="h-full w-full object-cover"
            />
            {product.featured && (
              <Badge className="absolute top-4 left-4 bg-[#FCD116] text-black hover:bg-[#FCD116]">
                Produit Vedette
              </Badge>
            )}
          </div>

          {/* Product Info */}
          <div className="space-y-6">
            <div>
              <h1 className="text-4xl font-bold text-gray-900 mb-2">
                {product.name}
              </h1>
              <Badge
                variant="outline"
                className="text-[#00A86B] border-[#00A86B]"
              >
                {product.category === 'electronics'
                  ? 'Électronique'
                  : product.category === 'fashion'
                  ? 'Mode'
                  : 'Maison'}
              </Badge>
            </div>

            <div className="text-4xl font-bold text-[#00A86B]">
              {formatPrice(product.price)}
            </div>

            <p className="text-gray-600 text-lg leading-relaxed">
              {product.description}
            </p>

            {product.inStock ? (
              <div className="flex items-center gap-2 text-green-600">
                <Package className="h-5 w-5" />
                <span className="font-medium">En stock</span>
              </div>
            ) : (
              <div className="flex items-center gap-2 text-red-600">
                <Package className="h-5 w-5" />
                <span className="font-medium">Rupture de stock</span>
              </div>
            )}

            <div className="flex gap-4">
