          </h1>
          <Link to="/products">
            <Button className="bg-[#00A86B] hover:bg-[#008f5d]">
              Retour aux produits
            </Button>
          </Link>
        </div>
      </div>
    );
  }

  const handleAddToCart = () => {
    addItem(product);
    toast.success('Produit ajouté au panier!');
  };

  const handleBuyNow = () => {
    addItem(product);
    navigate('/cart');
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <Header />

      <div className="container mx-auto px-4 py-8">
        <Button
          variant="ghost"
          onClick={() => navigate(-1)}
