  orders.push(order);
  return order;
};

export const updateOrderStatus = (
  orderId: string,
  orderStatus: Order['orderStatus'],
  paymentStatus?: Order['paymentStatus']
) => {
  const orderIndex = orders.findIndex((o) => o.id === orderId);
  if (orderIndex !== -1) {
