import { Link } from 'react-router-dom';

interface LogoProps {
  variant?: 'default' | 'text-only' | 'icon-only';
  className?: string;
  linkTo?: string;
}

export default function Logo({ variant = 'default', className = '', linkTo = '/' }: LogoProps) {
