# Sanii World - Plan de Migration V1

## 🎯 Objectif
Transformer le site e-commerce "DakarShop" existant en "Sanii World" - boutique de luxe minimaliste.

## 🎨 Design System
- **Nom**: Sanii World
- **Style**: Luxe minimaliste
- **Couleurs**:
  - Principales: Noir (#000000) / Blanc (#FFFFFF)
  - Accents: Or (#D4AF37) / Rose (#E91E63)
- **Logos**: 
  - `/public/brand/logo.png` (logo SW)
  - `/public/brand/logo-text.png` (texte SAMANI_WORLD)

## 📊 État Actuel (Audit)

### Structure Existante
```
✅ Components: Header, ProductCard, CategoryCard, CartItem, ProtectedRoute
✅ Pages Client: Index, Products, ProductDetail, Cart, Checkout, Profile, Login, Register, About
✅ Pages Admin: Dashboard, Products, Orders
✅ Stores: auth-store, cart-store, admin-products, orders-data
✅ Data: products-data (mock data avec 9 produits)
```

### Limitations Actuelles
❌ Pas de système de variantes (taille, couleur)
❌ Pas de sous-catégories
❌ Pas de gestion de stock par variante
❌ Pas de tracking de livraison
❌ Pas de système de retours/échanges
❌ Pas de wishlist
❌ Pas de coupons
❌ Catégories hardcodées (Electronics, Fashion, Home)
❌ Pas de galerie d'images produit
❌ Pas de recherche avancée
❌ Pas de filtres dynamiques

## 🗄️ Nouvelle Structure de Données

### Modèles à Créer (TypeScript Interfaces)

```typescript
// Categories & SubCategories
interface Category {
  id: string;
  name: string;
  slug: string;
  description?: string;
  image: string;
  parentId?: string; // Pour sous-catégories
  order: number;
  isActive: boolean;
}

// Product Options (Taille, Couleur, Matière, etc.)
interface ProductOption {
  id: string;
  name: string; // "Taille", "Couleur", "Matière"
  type: 'select' | 'color' | 'button';
  order: number;
}

interface ProductOptionValue {
  id: string;
  optionId: string;
  value: string; // "S", "M", "L", "Noir", "Rose"
  displayValue?: string;
  colorHex?: string; // Pour type color
  order: number;
}

// Product avec variantes
interface Product {
  id: string;
  name: string;
  slug: string;
  description: string;
  categoryId: string;
  subCategoryId?: string;
  basePrice: number;
  coverImage: string;
  gallery: string[];
  isFeatured: boolean;
  isNewArrival: boolean;
  isBestSeller: boolean;
  isActive: boolean;
  createdAt: string;
  updatedAt: string;
}

interface ProductVariant {
  id: string;
  productId: string;
  sku: string;
  optionValues: { optionId: string; valueId: string }[];
  price?: number; // Override basePrice si différent
  stock: number;
  isActive: boolean;
}

// Inventory
interface InventoryLog {
  id: string;
  variantId: string;
  quantity: number;
  type: 'in' | 'out' | 'adjustment';
  reason: string;
  createdAt: string;
}

// Orders avec variantes
interface OrderItem {
  id: string;
  orderId: string;
  productId: string;
  variantId: string;
  quantity: number;
  price: number;
  productName: string;
  variantDetails: string; // "Taille: M, Couleur: Noir"
}

interface Order {
  id: string;
  orderNumber: string;
  userId: string;
  customerName: string;
  customerEmail: string;
  customerPhone: string;
  shippingAddress: string;
  shippingMethod: 'click-collect' | 'dakar' | 'hors-dakar';
  shippingCost: number;
  subtotal: number;
  discount: number;
  total: number;
  paymentMethod: 'online' | 'on-delivery';
  paymentStatus: 'pending' | 'paid' | 'failed' | 'refunded';
  orderStatus: 'pending' | 'confirmed' | 'preparing' | 'ready' | 'shipped' | 'delivered' | 'cancelled';
  items: OrderItem[];
  couponCode?: string;
  notes?: string;
  createdAt: string;
  updatedAt: string;
}

// Shipping & Tracking
interface ShippingConfig {
  id: string;
  method: 'click-collect' | 'dakar' | 'hors-dakar';
  name: string;
  description: string;
  cost: number;
  estimatedDays: string;
  isActive: boolean;
}

interface Shipment {
  id: string;
  orderId: string;
  trackingNumber: string;
  carrier?: string;
  status: 'pending' | 'in-transit' | 'delivered' | 'failed';
  createdAt: string;
  deliveredAt?: string;
}

interface TrackingEvent {
  id: string;
  shipmentId: string;
  status: string;
  description: string;
  location?: string;
  timestamp: string;
}

// Returns & Exchanges
interface ReturnRequest {
  id: string;
  orderId: string;
  userId: string;
  type: 'return' | 'exchange';
  reason: string;
  items: { orderItemId: string; quantity: number }[];
  status: 'requested' | 'approved' | 'rejected' | 'received' | 'refunded' | 'exchanged';
  notes?: string;
  createdAt: string;
  updatedAt: string;
}

// Wishlist
interface WishlistItem {
  id: string;
  userId: string;
  productId: string;
  variantId?: string;
  createdAt: string;
}

// Coupons
interface Coupon {
  id: string;
  code: string;
  type: 'percentage' | 'fixed';
  value: number;
  minPurchase?: number;
  maxDiscount?: number;
  validFrom: string;
  validTo: string;
  usageLimit?: number;
  usageCount: number;
  isActive: boolean;
}

// Notifications
interface NotificationEvent {
  id: string;
  orderId: string;
  type: 'email' | 'whatsapp' | 'sms';
  event: 'order-confirmed' | 'preparing' | 'shipped' | 'delivered' | 'incident';
  recipient: string;
  message: string;
  status: 'pending' | 'sent' | 'failed';
  sentAt?: string;
  createdAt: string;
}
```

